SELECT

FROM reservation
WHERE hotel_id = #{hotelId}
AND check_in_date >= #{startDate}
AND check_out_date <= #{endDate}
AND is_delete = 0

SELECT IFNULL(SUM(room_count), 0)
FROM reservation
WHERE hotel_id = #{hotelId}
AND type_id = #{typeId}
AND status IN (1,2,4)
AND is_delete = 0
AND check_in_date < #{checkOutDate}
AND check_out_date > #{checkInDate}
